-- ShopHub catalog backup (explicit ids: cate1..cate20, pro1..pro94).
-- Rows: categories=20, products=94, product_variants=0
--
-- New Render / empty DB (recommended order):
--   1) Set DATABASE_URL to External host (…postgres.render.com) + ?sslmode=require from Render.
--   2) shop-backend: npx prisma migrate deploy
--   3) shop-backend: set SKIP_CATALOG_SEED=1 then npx prisma db seed (admin, locations, coupons; no Prisma catalog).
--   4) pgAdmin: run THIS file from BEGIN through COMMIT on that same database.
--
-- Migrations already create sequences + next_prefixed_id; this file uses CREATE SEQUENCE IF NOT EXISTS
-- and setval so new rows from the app do not collide with cate*/pro* ids.
--
-- Product reset: DELETE lines below remove order_items + products matching pro+digits, then re-insert.
-- WARNING: orders that reference those products lose those line items.
--
BEGIN;

DELETE FROM "order_items" WHERE "productId" ~ '^pro[0-9]+$';
DELETE FROM "products" WHERE "id" ~ '^pro[0-9]+$';

