-- No product_variants rows found.

-- After explicit prefixed ids (cate1…, pro1…), advance sequences so NEW rows from
-- next_prefixed_id() do not reuse the same suffix (unique violations / wrong ids).
-- Some databases have tables but never ran prisma migration 20260515180000_prefixed_id_db_defaults.
CREATE SEQUENCE IF NOT EXISTS categories_id_seq;
CREATE SEQUENCE IF NOT EXISTS products_id_seq;

-- setval() rejects 0 (sequence minvalue is 1). If no cate*/pro* rows match, use val=1, is_called=false so next nextval is 1.
SELECT setval('categories_id_seq', x.val, x.is_called)
FROM (
  SELECT
    CASE WHEN m IS NULL OR m < 1 THEN 1 ELSE m END AS val,
    (m IS NOT NULL AND m >= 1) AS is_called
  FROM (
    SELECT MAX((regexp_match("id", '^cate([0-9]+)$'))[1]::int) AS m
    FROM "categories"
    WHERE "id" ~ '^cate[0-9]+$'
  ) s
) x;
SELECT setval('products_id_seq', x.val, x.is_called)
FROM (
  SELECT
    CASE WHEN m IS NULL OR m < 1 THEN 1 ELSE m END AS val,
    (m IS NOT NULL AND m >= 1) AS is_called
  FROM (
    SELECT MAX((regexp_match("id", '^pro([0-9]+)$'))[1]::int) AS m
    FROM "products"
    WHERE "id" ~ '^pro[0-9]+$'
  ) s
) x;

COMMIT;
